async (params, browser) => {
  // Open job posting
  await browser.open(`${params.job_url}`)

  // Wait for job details
  await browser.waitForSelector('.jobs-unified-top-card, .job-details-jobs-unified-top-card__job-title, .top-card-layout__title', 15000)

  // Let page settle
  await browser.wait(2000)

  // Expand description
  const expand_description = await browser.evaluate(`const seeMore = document.querySelector('button[aria-label*="Show more"], button.jobs-description__footer-button'); if (seeMore) seeMore.click(); return { expanded: true }`)

  await browser.wait(1000)

  // Extract job details
  const job_details = await browser.evaluate(`const titleEl = document.querySelector('.job-details-jobs-unified-top-card__job-title h1, .jobs-unified-top-card__job-title, .top-card-layout__title'); const companyEl = document.querySelector('.job-details-jobs-unified-top-card__company-name a, .jobs-unified-top-card__company-name a, .topcard__org-name-link'); const locationEl = document.querySelector('.job-details-jobs-unified-top-card__bullet, .jobs-unified-top-card__bullet, .topcard__flavor--bullet'); const descEl = document.querySelector('.jobs-description__content, .jobs-description-content__text, .description__text'); const criteriaEls = document.querySelectorAll('.job-details-jobs-unified-top-card__job-insight span, .jobs-unified-top-card__workplace-type, li.job-criteria__item'); const criteria = []; criteriaEls.forEach(el => { const text = el.textContent.trim(); if (text && text.length < 100) criteria.push(text); }); return { title: titleEl ? titleEl.textContent.trim() : 'Unknown', company: companyEl ? companyEl.textContent.trim() : '', location: locationEl ? locationEl.textContent.trim() : '', description: descEl ? descEl.textContent.trim().slice(0, 2000) : '', job_criteria: criteria.slice(0, 10), url: window.location.href }`)

  return job_details
}
